var taskSchedulerII = function(tasks, space) {
    const ready = new Map();
    let day = 0;
    for (const t of tasks) {
        day += 1;
        if (ready.has(t)) day = Math.max(day, ready.get(t));
        ready.set(t, day + space + 1);
    }
    return day;
};
